  "actions/clearInvalid.js": "/**\r\n * Remove invalid libraries in one batched reactive update.\r\n */\r\nexport default async function clearInvalid(peagle) {\r\n  const state = peagle.state.values;\r\n  const invalid = state.libraries.filter((library) => library.status === 'invalid');\r\n\r\n  if (!invalid.length) {\r\n    await peagle.eagle.plugin.invokeFunc('notification.show', [{\r\n      title: 'Nothing to clear',\r\n      description: 'All libraries are valid',\r\n    }], {});\r\n    return;\r\n  }\r\n\r\n  const confirmed = await peagle.ext.invokeFunc('dialog.confirm', [`Remove ${invalid.length} invalid libraries?`], {\r\n    title: 'Clear Invalid',\r\n    confirmText: 'Remove',\r\n  });\r\n\r\n  if (!confirmed) {\r\n    return;\r\n  }\r\n\r\n  peagle.state.batch(() => {\r\n    state.libraries = state.libraries.filter((library) => library.status === 'valid');\r\n    state.filtered = [...state.libraries];\r\n  });\r\n\r\n  await peagle.eagle.plugin.invokeFunc('notification.show', [{\r\n    title: 'Done',\r\n    description: `Removed ${invalid.length} invalid libraries`,\r\n  }], {});\r\n}",
  "actions/filter.js": "/**\r\n * Filter the current recent library list by query.\r\n */\r\nexport default async function filter(peagle, [query]) {\r\n  const state = peagle.state.values;\r\n  const normalizedQuery = String(query ?? '').trim().toLowerCase();\r\n  state.filtered = !normalizedQuery\r\n    ? [...state.libraries]\r\n    : state.libraries.filter((library) =>\r\n        library.name.toLowerCase().includes(normalizedQuery) ||\r\n        library.path.toLowerCase().includes(normalizedQuery),\r\n      );\r\n}",
  "actions/open.js": "/**\r\n * Open one recent library through the host Eagle runtime.\r\n */\r\nexport default async function open(peagle, [library]) {\r\n  await peagle.eagle.plugin.invokeFunc('notification.show', [{\r\n    title: 'Opening Library',\r\n    description: `Opening ${library.name}...`,\r\n  }], {});\r\n  await peagle.eagle.web.invokeFunc('library.switch', [library.path], {});\r\n  await peagle.eagle.plugin.invokeFunc('notification.show', [{\r\n    title: 'Library Opened',\r\n    description: `Switched to ${library.name}`,\r\n  }], {});\r\n}",
  "actions/refresh.js": "/**\r\n * Refresh the recent library list and publish the rendered results slot state.\r\n */\r\nexport default async function refresh(peagle) {\r\n  const state = peagle.state.values;\r\n  await peagle.ext.invokeFunc('slot.loading', ['results'], { text: 'Loading...' });\r\n\r\n  const paths = await peagle.eagle.util.invokeFunc('getRecentLibraries', [], {});\r\n  const validated = await Promise.all(\r\n    paths.map(async (libPath, index) => {\r\n      const valid = !libPath.endsWith('Projects.library');\r\n      return {\r\n        id: `lib_${index}`,\r\n        name: libPath.split('/').pop().replace('.library', ''),\r\n        path: libPath,\r\n        status: valid ? 'valid' : 'invalid',\r\n        statusVariant: valid ? 'success' : 'error',\r\n      };\r\n    }),\r\n  );\r\n\r\n  peagle.state.batch(() => {\r\n    state.libraries = validated;\r\n    state.filtered = [...validated];\r\n  });\r\n}",
  "actions/remove.js": "/**\r\n * Remove one library from the in-memory recent list.\r\n */\r\nexport default async function remove(peagle, [library]) {\r\n  const state = peagle.state.values;\r\n  peagle.state.batch(() => {\r\n    state.libraries = state.libraries.filter((entry) => entry.id !== library.id);\r\n    state.filtered = state.filtered.filter((entry) => entry.id !== library.id);\r\n  });\r\n}",
